+    #[test]
+    fn write_evidence_artifacts_creates_files() {
+        let config = BenchmarkSuiteConfig {
+            seed: 42,
+            profiles: vec![ScaleProfile::Small],
+            families: vec![BenchmarkFamily::BootStorm],
+            thresholds: RegressionThresholds::default(),
